module multi_pipe_8bit(
    input clk,
    input rst_n,
    input mul_en_in,
    input mul_a,
    input mul_b,
    output mul_en_out,
    output reg mul_out
);
wire [15:0] a, b;
reg [7:0] a_reg, b_reg;
reg [15:0] mul_out_reg;
reg [15:0] sum;
reg [15:0] temp0, temp1, temp2, temp3, temp4, temp5, temp6, temp7;
assign a = (mul_en_in) ? mul_a : 8'b0;
assign b = (mul_en_in) ? mul_b : 8'b0;
assign mul_en_out = mul_en_out_reg[7];
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        mul_en_out_reg <= 8'b0;
    end
    else begin
        mul_en_out_reg <= {mul_en_out_reg[6:0], mul_en_in};
    end
end
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        a_reg <= 8'b0;
        b_reg <= 8'b0;
    end
    else begin
        a_reg <= a;
        b_reg <= b;
    end
end
always @(posedge clk) begin
    if(mul_en_in) begin
        temp0 <= (b_reg[0]) ? a_reg : 8'b0;
        temp1 <= (b_reg[1]) ? a_reg : 8'b0;
        temp2 <= (b_reg[2]) ? a_reg : 8'b0;
        temp3 <= (b_reg[3]) ? a_reg : 8'b0;
        temp4 <= (b_reg[4]) ? a_reg : 8'b0;
        temp5 <= (b_reg[5]) ? a_reg : 8'b0;
        temp6 <= (b_reg[6]) ? a_reg : 8'b0;
        temp7 <= (b_reg[7]) ? a_reg : 8'b0;
    end
    else begin
        temp0 <= temp0;
        temp1 <= temp1;
        temp2 <= temp2;
        temp3 <= temp3;
        temp4 <= temp4;
        temp5 <= temp5;
        temp6 <= temp6;
        temp7 <= temp7;
    end
end
always @(posedge clk) begin
    if(mul_en_in) begin
        sum[7:0] <= temp0 + temp1;
        sum[15:8] <= temp2 + temp3;
    end
    else begin
        sum <= sum;
    end
end
always @(posedge clk) begin
    if(mul_en_in) begin
        mul_out_reg <= sum[15:8] + sum[7:0];
    end
    else begin
        mul_out_reg <= mul_out_reg;
    end
end
always @(posedge clk) begin
    if(mul_en_in) begin
        mul_out <= mul_out_reg;
    end
    else begin
        mul_out <= 16'd0;
    end
end
endmodule
